// // This module implements a 4-bit binary counter with asynchronous reset functionality.
module binary_counter (
    input clk,
    input rst,
    output reg [3:0] count
);

  always @(posedge clk) begin
    if (rst == 1'b1) begin
      count <= 4'b0;
    end else begin
      count <= count + 1;
    end
  end

endmodule
